// export default Taskcard

import React, { useState } from 'react';

const Taskcard = ({ task }) => {
  const [subtask, setSubtask] = useState('');
  const [subtasks, setSubtasks] = useState([]);

  function addtask() {
    if (subtask.trim() === '') return;
    const newtask = {
      activity: subtask,
      id: Date.now()
    };
    setSubtasks(prev => [...prev, newtask]);
    setSubtask('');
  }

  function deletetask() {
    // Optional: You can add a deletion method for the entire task if needed.
    console.log('Delete task logic here');
  }

  return (
    <>
      <div className='task-card'>
        <div className='taskcard-header'>
          <div className='task-title'>
            {task.title}
          </div>
          <div className='task-icons'>
            <div className='sub-icon'>
              <button className='icon-button' onClick={addtask}>
                <img className='icon-img' src='/assets/add.png' alt="Add" />
              </button>
            </div>
            <div className='sub-icon'>
              <button onClick={deletetask} className='icon-button'>
                <img className='icon-img' src='/assets/delete.png' alt="Delete" />
              </button>
            </div>
          </div>
        </div>

        <div className='sub-input-row'>
          <input
            className='subtask-input'
            value={subtask}
            onChange={(e) => setSubtask(e.target.value)}
            placeholder='Enter sub task'
          />
        </div>

        <div className='sub-tasks'>
          {subtasks.map((sub) => (
            <div className='sub-task-items' key={sub.id}>
              <input type='checkbox' className='subtask-checkbox' />
              <span className='subtask-text'>{sub.activity}</span>
            </div>
          ))}
        </div>
      </div>
      <Stylesheet />
    </>
  );
};

const Stylesheet = () => {
  return (
    <style>{`
      .task-card {
        margin-bottom: 2rem;
        padding: 10px;
        background-color: var(--secondary-color);
        box-sizing: border-box;
        border-radius: 5px;
        width: 270px;
      }

      .taskcard-header {
        display: flex;
        align-items: center;
        justify-content: space-between;
        padding: 0 5px;
        min-height: 50px;
      }

      .task-icons {
        display: flex;
        align-items: center;
      }

      .icon-button {
        background: none;
        border: none;
        cursor: pointer;
      }

      .icon-img {
        height: 20px;
        width: 25px;
      }

      .task-title {
        width: 100px;
        word-wrap: break-word;
        overflow-wrap: break-word;
        white-space: normal;
        color: var(--font-text);
        font-family: 'Cedarville Cursive', cursive;
      }

      .sub-input-row {
        display: flex;
        justify-content: center;
        margin: 10px 0;
      }

      .subtask-input {
        padding: 8px;
        border: none;
        background-color: var(--flower-white);
        border-radius: 5px;
        width: 90%;
        font-family: 'Cedarville Cursive', cursive;
        color: var(--font-text);
      }

      .subtask-input:focus {
        outline: none;
      }

      .sub-tasks {
        display: flex;
        flex-direction: column;
        gap: 8px;
        padding: 5px;
      }

      .sub-task-items {
        display: flex;
        align-items: center;
        gap: 8px;
        background-color: var(--flower-white);
        border-radius: 5px;
        padding: 6px 10px;
      }

      .subtask-checkbox {
        appearance: none;
        width: 18px;
        height: 18px;
        border: 2px solid var(--button-border);
        border-radius: 4px;
        background-color: var(--secondary-color);
        cursor: pointer;
        position: relative;
      }

      .subtask-checkbox:checked::before {
        content: '\\2713';
        color: var(--font-text);
        font-size: 14px;
        position: absolute;
        top: -1px;
        left: 2px;
      }

      .subtask-text {
        color: var(--font-text);
        font-family: 'Cedarville Cursive', cursive;
      }
    `}</style>
  );
};

export default Taskcard;
